create or replace function public.finalize_org_document_upload(
  p_upload_intent_id uuid,
  p_type text,
  p_title text,
  p_description text default null
)
returns table (
  org_document_id uuid,
  org_document_version_id uuid,
  storage_object_id uuid,
  bucket text,
  object_path text,
  filename text
)
language plpgsql
security definer
set search_path = public
as $$
declare
  v_intent public.org_document_upload_intents%rowtype;
  v_storage_object_id uuid;
  v_doc_id uuid;
  v_version_id uuid;
  v_object_exists boolean;
begin
  if auth.uid() is null then
    raise exception 'Authentication required';
  end if;

  select *
  into v_intent
  from public.org_document_upload_intents
  where id = p_upload_intent_id
  for update;

  if not found then
    raise exception 'Upload intent not found';
  end if;

  if not public.is_org_member(v_intent.org_id) then
    raise exception 'Not a member of organization %', v_intent.org_id;
  end if;

  if v_intent.created_by <> auth.uid() then
    raise exception 'Upload intent does not belong to current user';
  end if;

  -- Resolve storage_object up front so the idempotency check can match it.
  select so.id into v_storage_object_id
