  if v_storage_object_id is not null then
    select od.id, odv.id
    into v_doc_id, v_version_id
    from public.org_document_versions odv
    join public.org_documents od on od.id = odv.org_document_id
    where odv.storage_object_id = v_storage_object_id
      and od.org_id = v_intent.org_id
    limit 1;

    if v_doc_id is not null then
      return query
      select v_doc_id, v_version_id, v_storage_object_id,
             v_intent.bucket, v_intent.object_path, v_intent.filename;
      return;
    end if;
  end if;

  select exists (
    select 1
    from storage.objects so
    where so.bucket_id = v_intent.bucket
      and so.name = v_intent.object_path
  )
  into v_object_exists;

  if not v_object_exists then
    raise exception 'Storage object is not accessible';
  end if;

  insert into public.storage_objects (
    bucket, object_path, filename, mime_type, size_bytes, uploaded_by
  )
  values (
    v_intent.bucket, v_intent.object_path, v_intent.filename,
    v_intent.mime_type, v_intent.size_bytes, v_intent.created_by
  )
  on conflict on constraint storage_objects_bucket_object_path_key do nothing;

  select so.id into v_storage_object_id
  from public.storage_objects so
  where so.bucket = v_intent.bucket
    and so.object_path = v_intent.object_path;

  if v_storage_object_id is null then
    raise exception 'Storage object linkage could not be resolved';
  end if;

  insert into public.org_documents (
    org_id, title, type, origin, description, created_by
  )
  values (
    v_intent.org_id,
    coalesce(nullif(trim(p_title), ''), v_intent.filename),
    coalesce(nullif(trim(p_type), ''), 'knowledge_base'),
    'uploaded',
    nullif(trim(p_description), ''),
    v_intent.created_by
  )
  returning id into v_doc_id;

  insert into public.org_document_versions (
    org_document_id, storage_object_id, version_number, is_current
  )
  values (v_doc_id, v_storage_object_id, 1, true)
  returning id into v_version_id;

  update public.org_document_upload_intents
  set finalized_at = coalesce(finalized_at, now())
  where id = v_intent.id;

  return query
  select v_doc_id, v_version_id, v_storage_object_id,
         v_intent.bucket, v_intent.object_path, v_intent.filename;
end;
$$;

revoke all on function public.finalize_org_document_upload(uuid, text, text, text) from public;
grant execute on function public.finalize_org_document_upload(uuid, text, text, text) to authenticated;
